//! The Aeon-12 tool economy: a visible stamina/score/syzygy layer on top of
//! the existing `max_tool_calls` budget (`agent_loop.rs`), designed to give
//! the model an in-context reason to reach for tools instead of narrating
//! them — there is no native `tool_choice` enforcement available (the brains
//! in `brain.rs` are plain chat-completion POSTs).
//!
//! The gauge itself is `godWeight(R, v) = R - min(v, R) + 1`, the same
//! Lean-proved meter from `open-source/gnosis-math/Gnosis/GodFormula.lean`
//! (conservation, ceiling, floor, antitonicity), specialized at the
//! monorepo's own `R = 12` ("Aeon-12") the way
//! `Gnosis.AeonTwelveCarrierList.GodTwelveSlice` already does. The two NEW
//! claims this module introduces on top of that meter — the risk-tiered vent
//! cost table (failure always vents more than success) and the syzygy
//! multiplier cap — are proved in
//! `open-source/gnosis-math/Gnosis/AeonEconomyToolLoop.lean`; keep the two
//! tables in sync if either changes.

use std::collections::HashSet;

use super::agent_tools::AgentIndexedTool;

/// Aeon-12 dial resolution: the default budget `R` fed to `god_weight`.
/// Matches the `R = 12` specialization proved in `AeonEconomyToolLoop.lean`
/// and `AeonTwelveCarrierList.lean`. Overridable via env for experimentation,
/// but only the default is Lean-backed — the system prompt always renders
/// the *current* ceiling (`R + 1`) rather than hardcoding "13", so it stays
/// honest under an override.
pub(crate) const R: u32 = 12;

/// The God Formula: `w(R, v) = R - min(v, R) + 1`. Never zero (floor `1`),
/// caps at `R + 1`, conserves `w + v = R + 1` while `v <= R`. See
/// `Gnosis.GodFormula.godWeight` for the Lean original and its proofs.
pub(crate) fn god_weight(r: u32, v: u32) -> u32 {
    r - v.min(r) + 1
}

pub(crate) fn max_stamina_default() -> u32 {
    std::env::var("MOONSHINE_AGENT_MAX_STAMINA")
        .ok()
        .and_then(|v| v.trim().parse::<u32>().ok())
        .filter(|v| *v > 0)
        .unwrap_or(R)
}

/// Kill-switch, matching `agent_tool_loop_enabled()`'s convention: set
/// `MOONSHINE_AGENT_ECONOMY=0` to fall back to the plain, un-gamified loop.
pub(crate) fn economy_enabled() -> bool {
    std::env::var("MOONSHINE_AGENT_ECONOMY")
        .map(|v| v.trim() != "0")
        .unwrap_or(true)
}

/// Risk tier used for both vent cost and base score. `classify_tool_risk`'s
/// six risk labels collapse into three tiers; ordering matters for the
/// syzygy "non-decreasing tier" rule (a read -> mutate chain is fine, a
/// mutate -> read chain never counts as a strong syzygy).
fn risk_tier(risk: &str) -> u8 {
    match risk {
        "read_only" => 0,
        "workspace_write" | "formal_claim" => 1,
        "destructive" | "vcs_mutation" | "network" => 2,
        _ => 1,
    }
}

/// Vent cost by tier and outcome. Mirrors
/// `AeonEconomyToolLoop.ventCost`/`ventCost_failure_exceeds_success` exactly —
/// keep the two tables in sync.
fn vent_cost(tier: u8, success: bool) -> u32 {
    match (tier, success) {
        (0, true) => 0,
        (0, false) => 1,
        (1, true) => 1,
        (1, false) => 3,
        (2, true) => 2,
        (2, false) => 6,
        (_, true) => 0,
        (_, false) => 1,
    }
}

/// Base score per successful call, before the syzygy multiplier.
fn tier_score(tier: u8) -> u32 {
    match tier {
        0 => 5,
        1 => 10,
        2 => 15,
        _ => 5,
    }
}

/// Syzygy multiplier in tenths (`10` = x1.0 .. `20` = x2.0, capped). Mirrors
/// `AeonEconomyToolLoop.syzygyMultiplierTenths` exactly.
fn syzygy_multiplier_tenths(chain_len: u32) -> u32 {
    match chain_len {
        0 | 1 => 10,
        2 => 15,
        _ => 20,
    }
}

/// Deterministic FNV-1a hash, used only to place a tool's domain on the
/// Aeon-12 dial — not a security hash, just a stable bucket assignment.
fn fnv1a(input: &str) -> u32 {
    let mut hash: u32 = 0x811c_9dc5;
    for byte in input.bytes() {
        hash ^= byte as u32;
        hash = hash.wrapping_mul(0x0100_0193);
    }
    hash
}

/// Place a tool on the `Fin 12` dial by its dominant domain (falling back to
/// namespace when no dominant domain is set). This hash-to-bucket mapping is
/// a pragmatic heuristic layered on top of the proved meter/chord math below
/// — it is not itself a Lean-proved structure.
fn domain_bucket(tool: &AgentIndexedTool) -> u8 {
    let key = tool
        .meta
        .dominant_domain
        .as_deref()
        .filter(|s| !s.is_empty())
        .unwrap_or(tool.meta.namespace.as_str());
    (fnv1a(key) % 12) as u8
}

/// Circular distance on `Fin 12`, the same shape as
/// `Gnosis.AeonCycleTwelveShadow.shortChord`: `min(|a-b|, 12-|a-b|)`, range
/// `0..=6`.
fn short_chord_distance(a: u8, b: u8) -> u8 {
    let d = if a > b { a - b } else { b - a };
    d.min(12 - d)
}

/// Cue-token set for citation comparison — the same tokenizer
/// `merge_candidate_tools` uses (stopword-filtered, len >= 3, deduped), so
/// "citing" a tool result means sharing meaningful tokens, not stopwords.
fn citation_tokens(text: &str) -> HashSet<String> {
    super::prompt_cue_tokens(text).into_iter().collect()
}

/// Canonical `(tool name, arguments)` signature for repeat-call detection.
/// `serde_json::Value`'s `Display` already emits object keys in sorted order
/// — this crate does not enable serde_json's `preserve_order` feature, so
/// `Value::Object` is `BTreeMap`-backed — which is good enough for an
/// equality check without a bespoke canonicalizer. (If `preserve_order` is
/// ever enabled, this needs a real recursive key-sort instead.)
fn call_signature(tool_name: &str, arguments: &serde_json::Value) -> (String, String) {
    (tool_name.to_string(), arguments.to_string())
}

/// Flat bonus for finishing on a cited result. Sized like a single tool
/// call's base score — big enough to matter, never scaled by the syzygy
/// multiplier or chain length, so it can't be out-chained by continuing
/// longer first; this rewards STOPPING, not stopping-after-a-long-chain.
const FINISHER_BONUS: u32 = 12;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum Transition {
    /// No prior successful call to compare against.
    First,
    /// Same-or-adjacent domain bucket, non-decreasing risk tier: the
    /// "discover -> inspect -> mutate" shape. Earns the climbing multiplier.
    Strong,
    /// Same neighborhood but not a clean escalation (or a slightly wider
    /// hop): the chain keeps counting, but this step scores at the neutral
    /// x1.0 baseline.
    Weak,
    /// A wide jump to an unrelated domain: resets the chain.
    Break,
}

fn classify_transition(last: Option<(u8, u8)>, bucket: u8, tier: u8) -> Transition {
    match last {
        None => Transition::First,
        Some((prev_bucket, prev_tier)) => {
            let distance = short_chord_distance(prev_bucket, bucket);
            if distance <= 1 && tier >= prev_tier {
                Transition::Strong
            } else if distance <= 3 {
                Transition::Weak
            } else {
                Transition::Break
            }
        }
    }
}

/// One session's running Aeon-12 tool-economy state: the vent-driven power
/// gauge, the unbounded score, and the syzygy chain. `vent` only ever
/// increases within a session — `god_weight` is proved antitone, so no regen
/// step is needed to stay formally clean; the gauge narrows what can be
/// called as it drains but (per `godWeight_pos`) never truly reaches zero.
#[derive(Debug, Clone)]
pub(crate) struct AgentEconomy {
    max_stamina: u32,
    vent: u32,
    pub(crate) score: u32,
    chain_len: u32,
    last: Option<(u8, u8)>,
    /// Salient tokens from the most recent successful tool result — a
    /// deliberately *separate* lifetime from `last`/`chain_len`: a later
    /// failure on a different tool breaks the syzygy chain but must not
    /// erase citation credit for a still-fresh successful result from
    /// earlier in the same turn-loop.
    last_result_tokens: Option<HashSet<String>>,
    /// The immediately preceding successful call's `(tool name, canonicalized
    /// arguments)` signature — catches an identical repeat (the model calling
    /// the exact same tool with the exact same arguments again instead of
    /// answering or trying something new). Adjacent-only, like `last`: a
    /// different call, or a failure, in between clears it, so a later
    /// legitimate retry of the same call is never penalized.
    last_call: Option<(String, String)>,
    pub(crate) winded: bool,
    pub(crate) last_event: String,
}

#[derive(Debug, Clone, Copy)]
pub(crate) struct EconomySummary {
    pub(crate) weight: u32,
    pub(crate) ceiling: u32,
    pub(crate) score: u32,
    pub(crate) winded: bool,
}

impl EconomySummary {
    /// Did this turn actually execute a tool? A tool success OR failure vents the
    /// gauge (`weight < ceiling`) and a cited result raises `score` — the mirror
    /// of `AgentEconomy::is_at_rest`. Used to keep tool-derived answers (live,
    /// stateful) OUT of the amplituhedron cache: caching "42 files" and replaying
    /// it station-free would go stale the moment the directory changes.
    pub(crate) fn used_tools(&self) -> bool {
        self.weight < self.ceiling || self.score > 0
    }
}

impl AgentEconomy {
    pub(crate) fn new(max_stamina: u32) -> Self {
        Self {
            max_stamina: max_stamina.max(1),
            vent: 0,
            score: 0,
            chain_len: 0,
            last: None,
            last_result_tokens: None,
            last_call: None,
            winded: false,
            last_event: String::new(),
        }
    }

    pub(crate) fn weight(&self) -> u32 {
        god_weight(self.max_stamina, self.vent.min(self.max_stamina))
    }

    pub(crate) fn ceiling(&self) -> u32 {
        self.max_stamina + 1
    }

    /// True before any tool call has succeeded or failed this session (turn
    /// 1's baseline: full power, no score, no chain). At rest the status
    /// block would only ever read the same static boilerplate, so callers
    /// skip injecting it — one less thing for a small/weak model to latch
    /// onto and echo back instead of answering or calling a tool.
    pub(crate) fn is_at_rest(&self) -> bool {
        self.vent == 0 && self.score == 0
    }

    pub(crate) fn summary(&self) -> EconomySummary {
        EconomySummary {
            weight: self.weight(),
            ceiling: self.ceiling(),
            score: self.score,
            winded: self.winded,
        }
    }

    fn vent(&mut self, amount: u32) {
        self.vent = self.vent.saturating_add(amount);
        self.winded = self.vent >= self.max_stamina;
    }

    pub(crate) fn record_success(
        &mut self,
        tool: &AgentIndexedTool,
        risk: &str,
        arguments: &serde_json::Value,
        result_text: &str,
    ) {
        let tier = risk_tier(risk);
        self.vent(vent_cost(tier, true));

        let signature = call_signature(&tool.name, arguments);
        let is_repeat = self.last_call.as_ref() == Some(&signature);
        self.last_call = Some(signature);
        if is_repeat {
            // The MCP call really did succeed (hence the ordinary
            // success-tier vent above), but an identical repeat produced no
            // NEW information — score it like a no-op and, like a failure,
            // break the syzygy chain so it can't be laundered into a
            // "productive" transition.
            self.chain_len = 0;
            self.last = None;
            self.last_result_tokens = Some(citation_tokens(result_text));
            self.last_event =
                "+0 (identical repeat call — no new information, chain broken)".to_string();
            return;
        }

        let bucket = domain_bucket(tool);
        let transition = classify_transition(self.last, bucket, tier);
        self.chain_len = match transition {
            Transition::Break | Transition::First => 1,
            Transition::Strong | Transition::Weak => self.chain_len + 1,
        };
        let multiplier_tenths = if transition == Transition::Strong {
            syzygy_multiplier_tenths(self.chain_len)
        } else {
            10
        };
        let gained = tier_score(tier) * multiplier_tenths / 10;
        self.score += gained;
        self.last = Some((bucket, tier));
        self.last_result_tokens = Some(citation_tokens(result_text));
        self.last_event = format!(
            "+{} (syzygy x{}.{}, chain {})",
            gained,
            multiplier_tenths / 10,
            multiplier_tenths % 10,
            self.chain_len
        );
    }

    pub(crate) fn record_failure(&mut self, risk: &str) {
        let tier = risk_tier(risk);
        self.vent(vent_cost(tier, false));
        self.chain_len = 0;
        self.last = None;
        self.last_call = None;
        self.last_event = "+0 (failed call — no gain, chain broken)".to_string();
    }

    /// Awarded once, when the turn's final plain-text answer actually cites
    /// the most recent successful tool result. `record_success` only ever
    /// rewards calling MORE tools (via the syzygy chain) — this is the
    /// counterweight that rewards stopping. Returns the amount gained (0 if
    /// no tool has succeeded yet this turn-loop, or the answer doesn't cite
    /// the result).
    pub(crate) fn award_finisher_if_citing(&mut self, answer: &str) -> u32 {
        let Some(result_tokens) = self.last_result_tokens.as_ref() else {
            return 0;
        };
        if result_tokens.is_empty() {
            return 0;
        }
        let answer_tokens = citation_tokens(answer);
        let overlap = answer_tokens.intersection(result_tokens).count();
        // Adaptive floor: a thin result (1 cue token) can't demand 2 shared
        // tokens, but a richer result needs >= 2 so one incidental shared
        // word doesn't trivially satisfy it.
        if overlap < result_tokens.len().min(2) {
            return 0;
        }
        self.score += FINISHER_BONUS;
        self.last_event = format!(
            "+{FINISHER_BONUS} (finisher — cited the tool result, {overlap} shared token(s))"
        );
        FINISHER_BONUS
    }
}

/// The game-framed block injected into the system prompt every turn. Carrot
/// framing is deliberate: there is no `tool_choice` enforcement available, so
/// this is the only lever that can make the model prefer calling a tool over
/// narrating one.
pub(crate) fn economy_status_block(economy: &AgentEconomy) -> String {
    let weight = economy.weight();
    let ceiling = economy.ceiling();
    let multiplier_tenths = syzygy_multiplier_tenths(economy.chain_len);
    let mut block = format!(
        "AEON-12 GAME STATE (real — it changes what you can do):\n\
Power: {weight}/{ceiling} | Score: {score} pts | Syzygy chain: x{whole}.{frac} ({chain_len} step(s))\n\
- Every tool call vents the dial. A FAILED call vents far more than a success, \
and mutating/destructive/network calls vent the most when they fail — read \
before you write. The dial can never hit true zero, but it narrows what \
you're allowed to touch as it drains.\n\
- Calling tools in the same neighborhood back to back (discover -> inspect -> \
mutate) is a SYZYGY: nearby chains multiply your score up to x2. A wide jump \
to an unrelated tool breaks the chain back to x1.\n\
- FINISHING pays too: once a tool call has succeeded, a final answer that \
cites its specific result earns a flat +12 finisher bonus. You don't need \
another tool call just to keep a chain going — cite the result and answer.\n",
        weight = weight,
        ceiling = ceiling,
        score = economy.score,
        whole = multiplier_tenths / 10,
        frac = multiplier_tenths % 10,
        chain_len = economy.chain_len,
    );
    if !economy.last_event.is_empty() {
        block.push_str("- Last action: ");
        block.push_str(&economy.last_event);
        block.push('\n');
    }
    if economy.winded {
        block.push_str(&format!(
            "\nTHE DIAL IS SPENT (power {weight}/{ceiling}). Only read-only tools \
are offered until you finish this answer — you cannot mutate anything right now.\n"
        ));
    }
    block
}

#[cfg(test)]
mod agent_economy_tests {
    use super::*;
    use super::super::agent_tools::ToolMeta;

    fn tool_with_domain(name: &str, namespace: &str, dominant_domain: &str) -> AgentIndexedTool {
        AgentIndexedTool {
            name: name.to_string(),
            description: String::new(),
            raw: serde_json::json!({}),
            name_lower: name.to_lowercase(),
            description_lower: String::new(),
            raw_lower: String::new(),
            meta: ToolMeta {
                namespace: namespace.to_string(),
                source_kind: "atomic".to_string(),
                stages: Vec::new(),
                domains: Vec::new(),
                dominant_domain: Some(dominant_domain.to_string()),
                authority_kind: "ordinary".to_string(),
                input_schema: serde_json::Value::Null,
                activation_keywords: Vec::new(),
            },
        }
    }

    #[test]
    fn god_weight_never_reaches_zero_and_conserves() {
        for v in 0..=20u32 {
            let w = god_weight(12, v);
            assert!(w >= 1, "weight floored below 1 at v={v}: {w}");
            assert_eq!(w + v.min(12), 13, "conservation failed at v={v}");
        }
    }

    #[test]
    fn failure_vents_more_than_success_at_every_tier() {
        for tier in 0..=2u8 {
            assert!(
                vent_cost(tier, false) > vent_cost(tier, true),
                "tier {tier} failure did not vent more than success"
            );
        }
    }

    #[test]
    fn close_domain_chain_earns_syzygy_multiplier() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        let b = tool_with_domain("local/read_file", "local", "filesystem");
        let c = tool_with_domain("local/write_file", "local", "filesystem");
        economy.record_success(&a, "read_only", &serde_json::json!({}), "listed 3 entries");
        economy.record_success(&b, "read_only", &serde_json::json!({}), "file contents");
        assert_eq!(economy.chain_len, 2);
        let score_after_two = economy.score;
        economy.record_success(&c, "workspace_write", &serde_json::json!({}), "wrote file");
        assert_eq!(economy.chain_len, 3);
        // Third step is a strong syzygy at x2.0: tier-1 base 10 * 2.0 = 20.
        assert_eq!(economy.score - score_after_two, 20);
    }

    #[test]
    fn wide_domain_jump_breaks_chain() {
        assert_eq!(
            classify_transition(Some((0, 0)), 6, 0),
            Transition::Break
        );
        assert_eq!(classify_transition(Some((0, 0)), 1, 0), Transition::Strong);
        assert_eq!(classify_transition(Some((0, 0)), 3, 0), Transition::Weak);
    }

    #[test]
    fn record_failure_grants_zero_score_and_resets_chain() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        let b = tool_with_domain("local/read_file", "local", "filesystem");
        economy.record_success(&a, "read_only", &serde_json::json!({}), "listed 3 entries");
        economy.record_success(&b, "read_only", &serde_json::json!({}), "file contents");
        assert_eq!(economy.chain_len, 2);
        let score_before = economy.score;
        economy.record_failure("destructive");
        assert_eq!(economy.score, score_before);
        assert_eq!(economy.chain_len, 0);
    }

    #[test]
    fn vent_reaching_cap_sets_winded_with_weight_floor_of_one() {
        let mut economy = AgentEconomy::new(12);
        for _ in 0..3 {
            economy.record_failure("destructive");
        }
        assert!(economy.winded);
        assert_eq!(economy.weight(), 1);
    }

    #[test]
    fn is_at_rest_only_before_the_first_success_or_failure() {
        let mut economy = AgentEconomy::new(12);
        assert!(economy.is_at_rest());
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        economy.record_success(&a, "read_only", &serde_json::json!({}), "listed 3 entries");
        assert!(!economy.is_at_rest());

        let mut failed = AgentEconomy::new(12);
        failed.record_failure("read_only");
        assert!(!failed.is_at_rest());
    }

    #[test]
    fn economy_status_block_surfaces_power_score_syzygy_and_winded_flag() {
        let mut economy = AgentEconomy::new(1);
        economy.record_failure("destructive");
        let block = economy_status_block(&economy);
        assert!(block.contains("Power"));
        assert!(block.contains("Score"));
        assert!(block.contains("Syzygy"));
        assert!(block.contains("WINDED") || block.contains("DIAL IS SPENT"));
    }

    #[test]
    fn economy_status_block_mentions_the_finisher_bonus() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        economy.record_success(&a, "read_only", &serde_json::json!({}), "listed 3 entries");
        let block = economy_status_block(&economy);
        assert!(block.contains("FINISHING") || block.contains("finisher"));
    }

    #[test]
    fn finisher_bonus_awarded_when_answer_cites_last_result() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        economy.record_success(
            &a,
            "read_only",
            &serde_json::json!({}),
            "Found entries: monorepo.toml, agent_loop.rs, agent_economy.rs",
        );
        let score_before = economy.score;
        let gained = economy
            .award_finisher_if_citing("There are 3 files: monorepo.toml, agent_loop.rs, agent_economy.rs.");
        assert_eq!(gained, FINISHER_BONUS);
        assert_eq!(economy.score, score_before + FINISHER_BONUS);
        assert!(economy.last_event.contains("finisher"));
    }

    #[test]
    fn finisher_bonus_not_awarded_without_a_prior_success() {
        let mut economy = AgentEconomy::new(12);
        let gained = economy.award_finisher_if_citing("The capital of France is Paris.");
        assert_eq!(gained, 0);
        assert_eq!(economy.score, 0);
    }

    #[test]
    fn finisher_bonus_requires_more_than_one_incidental_shared_word() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        economy.record_success(
            &a,
            "read_only",
            &serde_json::json!({}),
            "Found entries: monorepo.toml, agent_loop.rs, agent_economy.rs",
        );
        let score_before = economy.score;
        // Shares only "entries" — one incidental word is not a real citation.
        let gained = economy.award_finisher_if_citing("There are several entries here.");
        assert_eq!(gained, 0);
        assert_eq!(economy.score, score_before);
    }

    #[test]
    fn finisher_bonus_survives_a_later_unrelated_failure() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        economy.record_success(
            &a,
            "read_only",
            &serde_json::json!({}),
            "Found entries: monorepo.toml, agent_loop.rs, agent_economy.rs",
        );
        // A later failure on a different tool breaks the syzygy chain but
        // must not erase citation credit for the earlier successful result.
        economy.record_failure("destructive");
        let score_before = economy.score;
        let gained = economy
            .award_finisher_if_citing("There are 3 files: monorepo.toml, agent_loop.rs, agent_economy.rs.");
        assert_eq!(gained, FINISHER_BONUS);
        assert_eq!(economy.score, score_before + FINISHER_BONUS);
    }

    #[test]
    fn identical_repeat_call_earns_zero_score_and_breaks_chain() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        let args = serde_json::json!({"path": "/path/to/directory"});
        economy.record_success(&a, "read_only", &args, "listed 3 entries");
        assert_eq!(economy.chain_len, 1);
        let score_after_first = economy.score;
        economy.record_success(&a, "read_only", &args, "listed 3 entries");
        assert_eq!(economy.score, score_after_first);
        assert_eq!(economy.chain_len, 0);
        assert!(economy.last_event.contains("repeat"));
    }

    #[test]
    fn identical_repeat_still_vents_the_normal_success_cost() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        let args = serde_json::json!({"path": "/path/to/directory"});
        economy.record_success(&a, "read_only", &args, "listed 3 entries");
        let weight_after_first = economy.weight();
        economy.record_success(&a, "read_only", &args, "listed 3 entries");
        // read_only success costs 0 vent (see vent_cost), so weight is unchanged
        // by either call — the key assertion is it's the success cost, not the
        // much larger failure-tier cost, that would have dropped weight further.
        assert_eq!(economy.weight(), weight_after_first);
        assert!(!economy.winded);
    }

    #[test]
    fn same_tool_different_arguments_is_not_treated_as_a_repeat() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/read_file", "local", "filesystem");
        economy.record_success(
            &a,
            "read_only",
            &serde_json::json!({"path": "a.rs"}),
            "contents of a.rs",
        );
        assert_eq!(economy.chain_len, 1);
        let score_after_first = economy.score;
        economy.record_success(
            &a,
            "read_only",
            &serde_json::json!({"path": "b.rs"}),
            "contents of b.rs",
        );
        assert_eq!(economy.chain_len, 2);
        assert!(economy.score > score_after_first);
    }

    #[test]
    fn three_identical_repeats_in_a_row_all_score_zero() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        let args = serde_json::json!({"path": "/path/to/directory"});
        economy.record_success(&a, "read_only", &args, "listed 3 entries");
        let score_after_first = economy.score;
        economy.record_success(&a, "read_only", &args, "listed 3 entries");
        economy.record_success(&a, "read_only", &args, "listed 3 entries");
        assert_eq!(economy.score, score_after_first);
        assert_eq!(economy.chain_len, 0);
    }

    #[test]
    fn record_failure_clears_repeat_memory_so_a_retry_scores_normally() {
        let mut economy = AgentEconomy::new(12);
        let a = tool_with_domain("local/list_directory", "local", "filesystem");
        let args = serde_json::json!({"path": "/path/to/directory"});
        economy.record_success(&a, "read_only", &args, "listed 3 entries");
        economy.record_failure("destructive");
        let score_before = economy.score;
        // Same tool + same args as the first call, but a failure happened in
        // between — this must score as a fresh Strong/First transition, not
        // as a penalized repeat.
        economy.record_success(&a, "read_only", &args, "listed 3 entries");
        assert!(economy.score > score_before);
        assert!(!economy.last_event.contains("repeat"));
    }
}
